"intelephense.environment.includePaths": [
    "/home/<yourusername>/php-composer"
],

"remotefs.remote": {
    "bgadev": {
        "name": "BGA",
        "host": "1.studio.boardgamearena.com",
        "protocol": "sftp",
        "port": 2022,
        "username": "<yourdevusername>",
        "privateKeyPath": "~/.ssh/id_rsa",
    },
  }

{
    "remote": "bgadev",
    "remotePath": "/<yourproject>/",
    "uploadOnSave": true,
    "ignore": [
        ".git"
    ],
    "syncOption": {
        "skipCreate": false, 
        "delete": true 
    },
    "watcher": {
        "files": "**/*.{js,css}",
        "autoUpload": true,
        "autoDelete": true
    }
}

"devDependencies": {
    "@prettier/plugin-php": "^0.22",
    "prettier": "^3.6"
},
"prettier": {
  "plugins": ["@prettier/plugin-php"],
  "braceStyle": "1tbs",
  "printWidth": 140,
  "trailingComma": "none"
}

"emeraldwalk.runonsave": {
    "commands": [
        {
            "match": ".*\\.ts$",
            "isAsync": true,
            "cmd": "npm run build:ts"
        },
        {
            "match": ".*\\.scss$",
            "isAsync": true,
            "cmd": "npm run build:scss"
        }
    ]
}

{
  "match": "misc/.*material\\.csv$",
  "isAsync": true,
  "cmd": "php7.4 ${env.HOME}/git/bga-sharedcode/misc/genmat.php ${file}"
}

{
  "Player loop in game.php": {
    "prefix": ["players"],
    "body": [
      "\\$players = \\$this->loadPlayersBasicInfos();",
      "foreach (\\$players as \\$player_id => \\$player_info) {",
      "${1}",
      "}"
    ]
  }

}
